sql:
SELECT customer_age_group, COUNT(customer_id) AS total_customers
FROM customers
GROUP BY customer_age_group;

SELECT COUNT(*) AS purchase_count
FROM purchases
WHERE customer_id = 1;

SELECT COUNT(DISTINCT customer_id) AS unique_customers
FROM purchases
WHERE purchase_date >= '2023-01-01' AND purchase_date <= '2023-12-31';

SELECT COUNT(*) AS total_count
FROM virtual_fittings
WHERE fit_accuracy_rating > 3;

SELECT DISTINCT customer_id
FROM reviews
WHERE rating >= 4;

external_knowledge:
- "Captains of the purchasing ship" refers to customers who make significant purchases; 
- "Navigated through the most quantities in each size category" translates to customers with the highest total purchases in each size; 
- "Collecting treasure" metaphorically represents the process of acquiring or purchasing items.

